"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[710],{3214(n,r,t){t.r(r),t.d(r,{assets:()=>c,contentTitle:()=>o,default:()=>g,frontMatter:()=>s,metadata:()=>e,toc:()=>p});const e=JSON.parse('{"id":"cpp20/aggregate-parens-init","title":"\u5706\u62ec\u53f7\u805a\u5408\u521d\u59cb\u5316 (Parenthesized Aggregate Initialization)","description":"C++20 \u5706\u62ec\u53f7\u805a\u5408\u521d\u59cb\u5316 (Parenthesized Aggregate Initialization) \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp20/10-aggregate-parens-init.md","sourceDirName":"cpp20","slug":"/cpp20/10-aggregate-parens-init","permalink":"/LearnModernCpp/docs/cpp20/10-aggregate-parens-init","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp20","permalink":"/LearnModernCpp/docs/tags/cpp-20"},{"inline":true,"label":"aggregate_parens_init","permalink":"/LearnModernCpp/docs/tags/aggregate-parens-init"}],"version":"current","sidebarPosition":11,"frontMatter":{"sidebar_position":11,"slug":"10-aggregate-parens-init","title":"\u5706\u62ec\u53f7\u805a\u5408\u521d\u59cb\u5316 (Parenthesized Aggregate Initialization)","description":"C++20 \u5706\u62ec\u53f7\u805a\u5408\u521d\u59cb\u5316 (Parenthesized Aggregate Initialization) \u6559\u5b66\u793a\u4f8b","tags":["cpp20","aggregate_parens_init"]},"sidebar":"docs","previous":{"title":"\u6a21\u677f Lambda (Template Lambdas)","permalink":"/LearnModernCpp/docs/cpp20/09-template-lambdas"},"next":{"title":"Ranges \u57fa\u7840 (std::ranges \u7b97\u6cd5)","permalink":"/LearnModernCpp/docs/cpp20/20-ranges-basics"}}');var i=t(74848),a=t(28453);const s={sidebar_position:11,slug:"10-aggregate-parens-init",title:"\u5706\u62ec\u53f7\u805a\u5408\u521d\u59cb\u5316 (Parenthesized Aggregate Initialization)",description:"C++20 \u5706\u62ec\u53f7\u805a\u5408\u521d\u59cb\u5316 (Parenthesized Aggregate Initialization) \u6559\u5b66\u793a\u4f8b",tags:["cpp20","aggregate_parens_init"]},o="\u5706\u62ec\u53f7\u805a\u5408\u521d\u59cb\u5316 (Parenthesized Aggregate Initialization)",c={},p=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function d(n){const r={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,a.R)(),...n.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(r.header,{children:(0,i.jsx)(r.h1,{id:"\u5706\u62ec\u53f7\u805a\u5408\u521d\u59cb\u5316-parenthesized-aggregate-initialization",children:"\u5706\u62ec\u53f7\u805a\u5408\u521d\u59cb\u5316 (Parenthesized Aggregate Initialization)"})}),"\n",(0,i.jsx)(r.p,{children:"C++20 \u6807\u51c6\u5f15\u5165\u7684 \u5706\u62ec\u53f7\u805a\u5408\u521d\u59cb\u5316 (Parenthesized Aggregate Initialization) \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,i.jsx)(r.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,i.jsx)(r.pre,{children:(0,i.jsx)(r.code,{className:"language-cpp",metastring:'title="cpp20/10_aggregate_parens_init.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: \u5706\u62ec\u53f7\u805a\u5408\u521d\u59cb\u5316 (Parenthesized Aggregate Initialization)\r\n * \u6240\u5c5e\u6807\u51c6: C++20\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: C++20 \u5141\u8bb8\u4f7f\u7528\u5706\u62ec\u53f7 () \u5bf9\u805a\u5408\u4f53\u8fdb\u884c\u521d\u59cb\u5316\uff0c\r\n *          \u4e4b\u524d\u53ea\u80fd\u4f7f\u7528\u82b1\u62ec\u53f7 {} \u8fdb\u884c\u805a\u5408\u521d\u59cb\u5316\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: \u89e3\u51b3 make_shared/emplace_back \u7b49\u51fd\u6570\r\n *             \u65e0\u6cd5\u76f4\u63a5\u6784\u9020\u805a\u5408\u4f53\u7684\u95ee\u9898\uff0c\u56e0\u4e3a\u8fd9\u4e9b\u51fd\u6570\r\n *             \u5185\u90e8\u4f7f\u7528\u5706\u62ec\u53f7\u8fdb\u884c\u8f6c\u53d1\u6784\u9020\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - \u805a\u5408\u4f53\u53ef\u4ee5\u7528 () \u521d\u59cb\u5316\uff0c\u4f7f make_shared/emplace \u7b49\u51fd\u6570\u53ef\u7528\r\n *   - \u4e0e\u82b1\u62ec\u53f7\u521d\u59cb\u5316\u7684\u533a\u522b\uff1a\u5706\u62ec\u53f7\u4e0d\u68c0\u67e5\u7a84\u5316\u8f6c\u6362\r\n *   - \u5706\u62ec\u53f7\u521d\u59cb\u5316\u4e0d\u652f\u6301\u6307\u5b9a\u521d\u59cb\u5316\u5668\r\n *   - \u672a\u63d0\u4f9b\u7684\u6210\u5458\u4f1a\u88ab\u503c\u521d\u59cb\u5316\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <memory>\r\n#include <vector>\r\n#include <array>\r\n#include <string>\r\n#include <utility>\r\n\r\n// ===================== basic_usage() =====================\r\n\r\n// \u7b80\u5355\u805a\u5408\u4f53\r\nstruct Point {\r\n    int x;\r\n    int y;\r\n};\r\n\r\nstruct Color {\r\n    unsigned char r;\r\n    unsigned char g;\r\n    unsigned char b;\r\n    unsigned char a = 255;\r\n};\r\n\r\nstruct Config {\r\n    std::string name;\r\n    int width;\r\n    int height;\r\n};\r\n\r\nvoid basic_usage() {\r\n    std::cout << "--- \u57fa\u7840\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // C++17: \u53ea\u80fd\u7528\u82b1\u62ec\u53f7\u521d\u59cb\u5316\u805a\u5408\u4f53\r\n    Point p1{10, 20};\r\n    std::cout << "\u82b1\u62ec\u53f7\u521d\u59cb\u5316: Point{10, 20} = (" << p1.x << ", " << p1.y << ")\\n";\r\n\r\n    // C++20: \u53ef\u4ee5\u7528\u5706\u62ec\u53f7\u521d\u59cb\u5316\u805a\u5408\u4f53\r\n    Point p2(30, 40);\r\n    std::cout << "\u5706\u62ec\u53f7\u521d\u59cb\u5316: Point(30, 40) = (" << p2.x << ", " << p2.y << ")\\n";\r\n\r\n    // \u5173\u952e\u5e94\u7528\uff1amake_shared \u73b0\u5728\u53ef\u4ee5\u76f4\u63a5\u6784\u9020\u805a\u5408\u4f53\uff01\r\n    // C++17: std::make_shared<Point>(10, 20);  // \u7f16\u8bd1\u9519\u8bef\uff01\r\n    // C++20: \u5408\u6cd5!\r\n    auto ptr = std::make_shared<Point>(10, 20);\r\n    std::cout << "\\nmake_shared<Point>(10, 20): (" << ptr->x << ", " << ptr->y << ")\\n";\r\n\r\n    auto ptr2 = std::make_shared<Config>("\u7a97\u53e3", 800, 600);\r\n    std::cout << "make_shared<Config>(\\"\u7a97\u53e3\\", 800, 600): "\r\n              << ptr2->name << " " << ptr2->width << "x" << ptr2->height << "\\n";\r\n\r\n    // emplace_back \u4e5f\u53ef\u4ee5\u4e86\r\n    std::vector<Point> points;\r\n    points.emplace_back(1, 2);   // C++17 \u7f16\u8bd1\u9519\u8bef, C++20 \u5408\u6cd5\r\n    points.emplace_back(3, 4);\r\n    points.emplace_back(5, 6);\r\n\r\n    std::cout << "\\nemplace_back \u6784\u9020\u7684\u70b9: ";\r\n    for (const auto& p : points) {\r\n        std::cout << "(" << p.x << "," << p.y << ") ";\r\n    }\r\n    std::cout << "\\n";\r\n}\r\n\r\n// ===================== advanced_usage() =====================\r\n\r\n// \u5e26\u6570\u7ec4\u6210\u5458\u7684\u805a\u5408\u4f53\r\nstruct Matrix {\r\n    int data[4];\r\n};\r\n\r\n// \u7ee7\u627f\u7684\u805a\u5408\u4f53\r\nstruct Base {\r\n    int id;\r\n};\r\n\r\nstruct Derived : Base {\r\n    std::string name;\r\n};\r\n\r\n// \u5d4c\u5957\u805a\u5408\u4f53\r\nstruct Rect {\r\n    Point origin;\r\n    Point size;\r\n};\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- \u9ad8\u7ea7\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // make_unique \u4e5f\u53ef\u4ee5\u7528\u4e86\r\n    auto up = std::make_unique<Color>(255, 128, 0);\r\n    std::cout << "make_unique<Color>(255, 128, 0): "\r\n              << "r=" << (int)up->r << " g=" << (int)up->g\r\n              << " b=" << (int)up->b << " a=" << (int)up->a << "\\n";\r\n\r\n    // \u5728 optional \u4e2d\u4f7f\u7528\r\n    // std::optional<Point> opt(std::in_place, 10, 20);  // C++20 \u5408\u6cd5\r\n\r\n    // emplace \u7cfb\u5217\u51fd\u6570\r\n    std::vector<Config> configs;\r\n    configs.emplace_back("\u4e3b\u7a97\u53e3", 1920, 1080);\r\n    configs.emplace_back("\u526f\u7a97\u53e3", 800, 600);\r\n\r\n    std::cout << "\\n\u914d\u7f6e\u5217\u8868:\\n";\r\n    for (const auto& cfg : configs) {\r\n        std::cout << "  " << cfg.name << ": " << cfg.width << "x" << cfg.height << "\\n";\r\n    }\r\n\r\n    // \u82b1\u62ec\u53f7 vs \u5706\u62ec\u53f7\u7684\u533a\u522b\r\n    std::cout << "\\n-- \u82b1\u62ec\u53f7 vs \u5706\u62ec\u53f7 --\\n";\r\n\r\n    // \u82b1\u62ec\u53f7\u68c0\u67e5\u7a84\u5316\u8f6c\u6362\r\n    // Color c1{256, 0, 0};  // \u53ef\u80fd\u7684\u7a84\u5316\u8b66\u544a/\u9519\u8bef (256 \u8d85\u51fa unsigned char \u8303\u56f4)\r\n    // \u5706\u62ec\u53f7\u4e0d\u68c0\u67e5\u7a84\u5316\u8f6c\u6362\r\n    Color c2(256, 0, 0);     // \u5408\u6cd5\uff08\u4f46\u503c\u4f1a\u88ab\u622a\u65ad\uff09\r\n    std::cout << "\u5706\u62ec\u53f7 Color(256, 0, 0): r=" << (int)c2.r\r\n              << " (\u53d1\u751f\u622a\u65ad\uff0c256\u2192" << (int)c2.r << ")\\n";\r\n\r\n    // \u6570\u7ec4\u6210\u5458 \u2014\u2014 \u6ce8\u610f\uff1a\u5305\u542b\u6570\u7ec4\u7684\u805a\u5408\u4f53\u4e0d\u80fd\u7528\u5706\u62ec\u53f7\u521d\u59cb\u5316\r\n    Matrix m{1, 2, 3, 4};  // \u82b1\u62ec\u53f7\u4ecd\u53ef\u7528\r\n    std::cout << "\\nMatrix{1,2,3,4}: ";\r\n    for (int v : m.data) std::cout << v << " ";\r\n    std::cout << "\\n";\r\n\r\n    // unique_ptr \u6570\u7ec4\r\n    auto arr_ptr = std::make_unique<Point[]>(3);\r\n    // \u6ce8\u610f\uff1amake_unique \u6570\u7ec4\u7248\u672c\u4e0d\u652f\u6301\u53c2\u6570\u521d\u59cb\u5316\r\n    std::cout << "\\nmake_unique<Point[]>(3): \u6570\u7ec4\u5df2\u521b\u5efa\\n";\r\n}\r\n\r\n// ===================== pitfalls() =====================\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- \u6613\u9519\u70b9 ---\\n\\n";\r\n\r\n    // \u9677\u96311\uff1a\u5706\u62ec\u53f7\u4e0d\u68c0\u67e5\u7a84\u5316\u8f6c\u6362\r\n    std::cout << "1. \u5706\u62ec\u53f7\u521d\u59cb\u5316\u4e0d\u68c0\u67e5\u7a84\u5316\u8f6c\u6362:\\n";\r\n    std::cout << "   Point p{3.14, 2.71};  // \u82b1\u62ec\u53f7: \u7a84\u5316\u9519\u8bef!\\n";\r\n    std::cout << "   Point p(3.14, 2.71);  // \u5706\u62ec\u53f7: \u5408\u6cd5\uff0c\u4f46\u622a\u65ad\u4e3a (3, 2)\\n";\r\n    Point p_narrow(3.14, 2.71);\r\n    std::cout << "   \u5b9e\u9645\u7ed3\u679c: (" << p_narrow.x << ", " << p_narrow.y << ")\\n\\n";\r\n\r\n    // \u9677\u96312\uff1a\u5706\u62ec\u53f7\u4e0d\u80fd\u4f7f\u7528\u6307\u5b9a\u521d\u59cb\u5316\u5668\r\n    std::cout << "2. \u5706\u62ec\u53f7\u4e0d\u652f\u6301\u6307\u5b9a\u521d\u59cb\u5316\u5668:\\n";\r\n    std::cout << "   Point p{.x=1, .y=2};  // \u82b1\u62ec\u53f7: \u5408\u6cd5\\n";\r\n    std::cout << "   Point p(.x=1, .y=2);  // \u5706\u62ec\u53f7: \u7f16\u8bd1\u9519\u8bef!\\n\\n";\r\n\r\n    // \u9677\u96313\uff1a\u4e0e\u6700\u4ee4\u4eba\u56f0\u6270\u7684\u89e3\u6790\uff08most vexing parse\uff09\u7684\u5173\u7cfb\r\n    std::cout << "3. \u6ce8\u610f most vexing parse:\\n";\r\n    std::cout << "   Point p();   // \u8fd9\u662f\u51fd\u6570\u58f0\u660e\uff0c\u4e0d\u662f\u53d8\u91cf\u5b9a\u4e49!\\n";\r\n    std::cout << "   Point p{};   // \u8fd9\u662f\u53d8\u91cf\u5b9a\u4e49\uff08\u96f6\u521d\u59cb\u5316\uff09\\n";\r\n    std::cout << "   Point p(1, 2); // \u8fd9\u662f\u53d8\u91cf\u5b9a\u4e49\uff08C++20 \u805a\u5408\u521d\u59cb\u5316\uff09\\n\\n";\r\n\r\n    // \u9677\u96314\uff1a\u672a\u63d0\u4f9b\u7684\u6210\u5458\r\n    std::cout << "4. \u672a\u63d0\u4f9b\u7684\u5c3e\u90e8\u6210\u5458\u4f1a\u88ab\u503c\u521d\u59cb\u5316\uff08\u96f6\u521d\u59cb\u5316\u6216\u9ed8\u8ba4\u6784\u9020\uff09:\\n";\r\n    Color partial(128);  // g=0, b=0, a=255\uff08\u4f7f\u7528\u9ed8\u8ba4\u503c\uff09\r\n    std::cout << "   Color(128): r=" << (int)partial.r\r\n              << " g=" << (int)partial.g\r\n              << " b=" << (int)partial.b\r\n              << " a=" << (int)partial.a << "\\n\\n";\r\n\r\n    // \u9677\u96315\uff1a\u53ea\u9002\u7528\u4e8e\u805a\u5408\u4f53\r\n    std::cout << "5. \u53ea\u6709\u805a\u5408\u4f53\u624d\u80fd\u4f7f\u7528\u5706\u62ec\u53f7\u805a\u5408\u521d\u59cb\u5316:\\n";\r\n    std::cout << "   \u6709\u7528\u6237\u5b9a\u4e49\u6784\u9020\u51fd\u6570\u7684\u7c7b\u578b\u7528\u5706\u62ec\u53f7\u662f\u8c03\u7528\u6784\u9020\u51fd\u6570\\n";\r\n    std::cout << "   \uff08\u8fd9\u4e0d\u662f\u65b0\u7279\u6027\uff0c\u4e00\u76f4\u5c31\u662f\u8fd9\u6837\uff09\\n";\r\n}\r\n\r\n// ===================== main() =====================\r\nint main() {\r\n    std::cout << "===== \u5706\u62ec\u53f7\u805a\u5408\u521d\u59cb\u5316 - C++20 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,i.jsx)(r.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,i.jsxs)(r.ul,{children:["\n",(0,i.jsx)(r.li,{children:(0,i.jsx)(r.a,{href:"https://en.cppreference.com/w/cpp/language/direct_initialization",children:"cppreference: \u5706\u62ec\u53f7\u805a\u5408\u521d\u59cb\u5316 (Parenthesized Aggregate Initialization)"})}),"\n"]})]})}function g(n={}){const{wrapper:r}={...(0,a.R)(),...n.components};return r?(0,i.jsx)(r,{...n,children:(0,i.jsx)(d,{...n})}):d(n)}},28453(n,r,t){t.d(r,{R:()=>s,x:()=>o});var e=t(96540);const i={},a=e.createContext(i);function s(n){const r=e.useContext(a);return e.useMemo(function(){return"function"==typeof n?n(r):{...r,...n}},[r,n])}function o(n){let r;return r=n.disableParentContext?"function"==typeof n.components?n.components(i):n.components||i:s(n.components),e.createElement(a.Provider,{value:r},n.children)}}}]);